	dst.G = texture.G*modulate.G*modulate.A + dst.G*(1.0-texture.G*modulate.A)
	dst.B = texture.B*modulate.B*modulate.A + dst.B*(1.0-texture.B*modulate.A)
	dst.A = modulate.A + dst.A*(1.0-modulate.A)

